import React, { useEffect, useState } from 'react';
import api from '../api';

const AdminDashboard = () => {
  const [dashboard, setDashboard] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const loadData = async () => {
      try {
        setLoading(true);
        const res = await api.get('dashboard');
        setDashboard(res.data);
        setError('');
      } catch (err) {
        console.error('Dashboard load error:', err);
        const msg = err.response?.data?.message || err.message || 'Failed to load dashboard';
        setError(msg);
      } finally {
        setLoading(false);
      }
    };

    loadData();
  }, []);

  const toggleBlock = async (userId, blocked) => {
    try {
      await api.put(`admin/users/${userId}/${blocked ? 'unblock' : 'block'}`);
      setUsers(users.map((u) => (u.id === userId ? { ...u, blocked: !blocked } : u)));
    } catch (err) {
      console.error(err);
    }
  };

  return (
    <div>
      <h2>My Dashboard</h2>

      {loading && <p>Loading dashboard...</p>}
      {error && !loading && <p style={{ color: 'red' }}>Error: {error}</p>}

      {dashboard && (
        <>
          <div style={{ border: '1px solid #ccc', borderRadius: 8, padding: 12, marginBottom: 16, width: 'fit-content' }}>
            <h3>User Info</h3>
            <p><strong>ID:</strong> {dashboard.userId || localStorage.getItem('userId') || 'N/A'}</p>
            <p><strong>Name:</strong> {dashboard.userName || localStorage.getItem('userName') || 'Unknown User'}</p>
            <p><strong>Email:</strong> {dashboard.userEmail || localStorage.getItem('userEmail') || 'Unknown Email'}</p>
          </div>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, minmax(0, 1fr))', gap: 12, marginBottom: 24 }}>
            <div style={{ border: '1px solid #ccc', borderRadius: 8, padding: 12 }}>
              <h4>Total Products Listed</h4>
              <p>{dashboard.totalProductsListed}</p>
            </div>
            <div style={{ border: '1px solid #ccc', borderRadius: 8, padding: 12 }}>
              <h4>Total Chats</h4>
              <p>{dashboard.totalChats}</p>
            </div>
          </div>

          <section>
            <h3>My Listings</h3>
            {dashboard.myListings.length ? dashboard.myListings.map((p) => (
              <div key={p.id} style={{ border: '1px solid #ddd', padding: 8, borderRadius: 6, marginBottom: 8 }}>
                {p.title} - ₹{p.price} - {p.sold ? 'Sold' : 'Available'}
              </div>
            )) : <p>No listings yet.</p>}
          </section>

          <section>
            <h3>My Purchases</h3>
            {dashboard.myPurchases.length ? dashboard.myPurchases.map((p) => (
              <div key={p.id} style={{ border: '1px solid #ddd', padding: 8, borderRadius: 6, marginBottom: 8 }}>
                {p.title} - ₹{p.price}
              </div>
            )) : <p>No purchases yet.</p>}
          </section>

          <section>
            <h3>Contacted Products</h3>
            {dashboard.contactedProducts.length ? dashboard.contactedProducts.map((p) => (
              <div key={p.id} style={{ border: '1px solid #ddd', padding: 8, borderRadius: 6, marginBottom: 8 }}>
                {p.title} - Seller: {p.sellerName}
              </div>
            )) : <p>No contacted products.</p>}
          </section>
        </>
      )}
    </div>
  );
};

export default AdminDashboard;
